1	import path from "path"
2	import { getRegistriesIndex } from "@/src/registry/api"
3	import { BUILTIN_REGISTRIES } from "@/src/registry/constants"
4	import { resolveRegistryNamespaces } from "@/src/registry/namespaces"
5	import { rawConfigSchema } from "@/src/registry/schema"
6	import { Config } from "@/src/utils/get-config"
7	import { spinner } from "@/src/utils/spinner"
8	import fs from "fs-extra"
9	
10	export async function ensureRegistriesInConfig(
11	  components: string[],
12	  config: Config,
13	  options: {
14	    silent?: boolean
15	    writeFile?: boolean
16	  } = {}
17	) {
18	  options = {
19	    silent: false,
20	    writeFile: true,
21	    ...options,
22	  }
23	
24	  // Use resolveRegistryNamespaces to discover all namespaces including dependencies.
25	  const registryNames = await resolveRegistryNamespaces(components, config)
26	
27	  const missingRegistries = registryNames.filter(
28	    (registry) =>
29	      !config.registries?.[registry] &&
30	      !Object.keys(BUILTIN_REGISTRIES).includes(registry)
31	  )
32	
33	  if (missingRegistries.length === 0) {
34	    return {
35	      config,
36	      newRegistries: [],
37	    }
38	  }
39	
40	  // We'll fail silently if we can't fetch the registry index.
41	  // The error handling by caller will guide user to add the missing registries.
42	  const registryIndex = await getRegistriesIndex({
43	    useCache: process.env.NODE_ENV !== "development",
44	  })
45	
46	  if (!registryIndex) {
47	    return {
48	      config,
49	      newRegistries: [],
50	    }
51	  }
52	
53	  const foundRegistries: Record<string, string> = {}
54	  for (const registry of missingRegistries) {
55	    if (registryIndex[registry]) {
56	      foundRegistries[registry] = registryIndex[registry]
57	    }
58	  }
59	
60	  if (Object.keys(foundRegistries).length === 0) {
61	    return {
62	      config,
63	      newRegistries: [],
64	    }
65	  }
66	
67	  // Filter out built-in registries from existing config before merging
68	  const existingRegistries = Object.fromEntries(
69	    Object.entries(config.registries || {}).filter(
70	      ([key]) => !Object.keys(BUILTIN_REGISTRIES).includes(key)
71	    )
72	  )
73	
74	  const newConfigWithRegistries = {
75	    ...config,
76	    registries: {
77	      ...existingRegistries,
78	      ...foundRegistries,
79	    },
80	  }
81	
82	  if (options.writeFile) {
83	    const { resolvedPaths, ...configWithoutResolvedPaths } =
84	      newConfigWithRegistries
85	    const configSpinner = spinner("Updating components.json.", {
86	      silent: options.silent,
87	    }).start()
88	    const updatedConfig = rawConfigSchema.parse(configWithoutResolvedPaths)
89	    await fs.writeFile(
90	      path.resolve(config.resolvedPaths.cwd, "components.json"),
91	      JSON.stringify(updatedConfig, null, 2) + "\n",
92	      "utf-8"
93	    )
94	    configSpinner.succeed()
95	  }
96	
97	  return {
98	    config: newConfigWithRegistries,
99	    newRegistries: Object.keys(foundRegistries),
100	  }
101	}
102	

