### 7. Registry Schema (Zod Validation)

**File:** `/packages/shadcn/src/registry/schema.ts`

Core types:
```typescript
export const registryItemTypeSchema = z.enum([
  "registry:lib",
  "registry:block",
  "registry:component",
  "registry:ui",
  "registry:hook",
  "registry:page",
  "registry:file",
  "registry:theme",
  "registry:style",
  "registry:item",
  "registry:base",
  "registry:font",
  "registry:example",
  "registry:internal",
])

export const registryItemCommonSchema = z.object({
  $schema: z.string().optional(),
  extends: z.string().optional(),
  name: z.string(),
  title: z.string().optional(),
  author: z.string().min(2).optional(),
  description: z.string().optional(),
  dependencies: z.array(z.string()).optional(),
  devDependencies: z.array(z.string()).optional(),
  registryDependencies: z.array(z.string()).optional(),
  files: z.array(registryItemFileSchema).optional(),
  tailwind: registryItemTailwindSchema.optional(),
  cssVars: registryItemCssVarsSchema.optional(),
  css: registryItemCssSchema.optional(),
  envVars: registryItemEnvVarsSchema.optional(),
  meta: z.record(z.string(), z.any()).optional(),
  docs: z.string().optional(),
  categories: z.array(z.string()).optional(),
})

export type RegistryItem = z.infer<typeof registryItemSchema>
export type Registry = z.infer<typeof registrySchema>
```

---

### 8. Registry Aggregation

**File:** `/apps/v4/registry/bases/radix/registry.ts`

How everything is combined:
```typescript
import { registryItemSchema, type Registry } from "shadcn/schema"
import { z } from "zod"

import { blocks } from "./blocks/_registry"
import { components } from "./components/_registry"
import { examples } from "./examples/_registry"
import { hooks } from "./hooks/_registry"
import { internal } from "./internal/_registry"
import { lib } from "./lib/_registry"
import { ui } from "./ui/_registry"

const RADIX_STYLE = {
  type: "registry:style",
  dependencies: ["class-variance-authority", "lucide-react", "radix-ui"],
  devDependencies: ["tw-animate-css", "shadcn"],
  registryDependencies: ["utils"],
  // ... CSS and config
}

export const registry = {
  name: "shadcn/ui",
  homepage: "https://ui.shadcn.com",
  items: z.array(registryItemSchema).parse([
    {
      name: "index",
      ...RADIX_STYLE,
    },
    {
      name: "style",
      ...RADIX_STYLE,
    },
    ...ui,              // UI components
    ...examples,        // Examples
    ...lib,             // Library utilities
    ...components,      // Complex components
    ...internal,        // Internal utilities
    ...blocks,          // Template blocks
    ...hooks,           // Custom hooks
    ...fonts,           // Font definitions
  ]),
} satisfies Registry
```

**Pattern:** All registry items from different categories (ui, examples, lib, components, etc.) are spread into a single array. This creates one unified registry.

