"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepStatus = "completed" | "active" | "incomplete"
type StepperOrientation = "horizontal" | "vertical"

// ─── StepperContext ───────────────────────────────────────────────────────────

interface StepperContextValue {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
  linear: boolean
  getStepStatus: (step: string) => StepStatus
  getStepIndex: (step: string) => number
  registerStep: (step: string) => () => void
  canNavigateTo: (step: string) => boolean
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper>")
  }
  return context
}

// ─── StepperItemContext ───────────────────────────────────────────────────────

interface StepperItemContextValue {
  step: string
  status: StepStatus
  index: number
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem>")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: StepperOrientation
  linear?: boolean
}

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  linear = false,
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const value = valueProp !== undefined ? valueProp : internalValue

  // stepOrder holds step ids in their registration (DOM) order so we can
  // compute "completed / active / incomplete" status for each step.
  const [stepOrder, setStepOrder] = React.useState<string[]>([])

  const registerStep = React.useCallback((step: string) => {
    setStepOrder((prev) => {
      if (prev.includes(step)) return prev
      return [...prev, step]
    })
    return () => {
      setStepOrder((prev) => prev.filter((s) => s !== step))
    }
  }, [])

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (valueProp === undefined) setInternalValue(newValue)
      onValueChange?.(newValue)
    },
    [valueProp, onValueChange]
  )

  const getStepStatus = React.useCallback(
    (step: string): StepStatus => {
      const currentIndex = stepOrder.indexOf(value)
      const stepIndex = stepOrder.indexOf(step)
      if (stepIndex < 0 || currentIndex < 0) return "incomplete"
      if (stepIndex < currentIndex) return "completed"
      if (stepIndex === currentIndex) return "active"
      return "incomplete"
    },
    [value, stepOrder]
  )

  const getStepIndex = React.useCallback(
    (step: string): number => stepOrder.indexOf(step) + 1,
    [stepOrder]
  )

  const canNavigateTo = React.useCallback(
    (step: string): boolean => {
      if (!linear) return true
      const currentIndex = stepOrder.indexOf(value)
      const stepIndex = stepOrder.indexOf(step)
      // In linear mode allow any prior step and the immediate next step only.
      return stepIndex <= currentIndex + 1
    },
    [value, stepOrder, linear]
  )

  return (
    <StepperContext.Provider
      value={{
        value,
        onValueChange: handleValueChange,
        orientation,
        linear,
        getStepStatus,
        getStepIndex,
        registerStep,
        canNavigateTo,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal" &&
            "flex-row flex-wrap items-start gap-y-6",
          orientation === "vertical" && "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: string
}

function StepperItem({ step, className, ...props }: StepperItemProps) {
  const { getStepStatus, getStepIndex, registerStep, orientation } =
    useStepper()

  // Register this step in DOM order so the parent can compute ordering.
  // useLayoutEffect fires synchronously before paint, so React 18's automatic
  // batching ensures all siblings register before the first visible frame.
  React.useLayoutEffect(() => {
    return registerStep(step)
  }, [step, registerStep])

  const status = getStepStatus(step)
  const index = getStepIndex(step)

  return (
    <StepperItemContext.Provider value={{ step, status, index }}>
      <div
        data-slot="stepper-item"
        data-status={status}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          orientation === "horizontal" &&
            "min-w-0 flex-1 flex-row items-center gap-2",
          orientation === "vertical" && "flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  onClick,
  disabled,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange, canNavigateTo } = useStepper()
  const { step, status, index } = useStepperItem()

  const navigable = canNavigateTo(step) && !disabled

  function handleClick(e: React.MouseEvent<HTMLButtonElement>) {
    if (navigable) {
      onValueChange(step)
    }
    onClick?.(e)
  }

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-status={status}
      disabled={!navigable}
      onClick={handleClick}
      className={cn(
        "cn-stepper-trigger group/stepper-trigger flex shrink-0 items-center gap-3 rounded outline-none transition-colors",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {/* Auto-rendered step indicator (circle with number or check icon) */}
      <span
        data-slot="stepper-indicator"
        data-status={status}
        className={cn(
          "cn-stepper-indicator flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
          status === "completed" &&
            "border-primary bg-primary text-primary-foreground",
          status === "active" && "border-primary text-primary",
          status === "incomplete" &&
            "border-muted-foreground/30 text-muted-foreground"
        )}
      >
        {status === "completed" ? (
          <IconPlaceholder
            lucide="CheckIcon"
            tabler="IconCheck"
            hugeicons="CheckmarkCircle01Icon"
            phosphor="CheckIcon"
            remixicon="RiCheckLine"
            className="size-4"
          />
        ) : (
          <span>{index}</span>
        )}
      </span>

      {/* Optional label content (StepperTitle / StepperDescription) */}
      {children && (
        <span
          data-slot="stepper-trigger-content"
          className="flex flex-col gap-0.5 text-left"
        >
          {children}
        </span>
      )}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  const { status } = useStepperItem()
  return (
    <span
      data-slot="stepper-title"
      data-status={status}
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        status === "active" && "text-foreground",
        status === "completed" && "text-foreground",
        status === "incomplete" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { status } = useStepperItem()
  return (
    <span
      data-slot="stepper-description"
      data-status={status}
      className={cn(
        "cn-stepper-description text-xs leading-none",
        status === "active" || status === "completed"
          ? "text-muted-foreground"
          : "text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  // Status comes from the item context if the separator is placed inside a
  // StepperItem; falls back to "incomplete" when used standalone.
  const itemContext = React.useContext(StepperItemContext)
  const status = itemContext?.status ?? "incomplete"

  return (
    <div
      role="none"
      data-slot="stepper-separator"
      data-status={status}
      data-orientation={orientation}
      className={cn(
        "cn-stepper-separator rounded-full bg-border transition-colors",
        status === "completed" && "bg-primary",
        orientation === "horizontal" && "h-0.5 min-w-4 flex-1",
        orientation === "vertical" && "ms-4 mt-1 min-h-8 w-0.5",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

interface StepperContentProps extends React.ComponentProps<"div"> {
  /** Explicit step identifier. Required when rendered outside a StepperItem. */
  step?: string
}

function StepperContent({
  step: stepProp,
  className,
  ...props
}: StepperContentProps) {
  const { value, orientation } = useStepper()
  const itemContext = React.useContext(StepperItemContext)

  // Resolve step from explicit prop or, when nested, from the item context.
  const step = stepProp ?? itemContext?.step
  const isActive = step !== undefined && step === value

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(
        "cn-stepper-content",
        // Horizontal: full-width row below all step triggers (needs flex-wrap
        // on the Stepper root to push this onto its own line).
        orientation === "horizontal" && "w-full basis-full pt-2",
        // Vertical: indented beneath the trigger text column.
        orientation === "vertical" && "ms-11 pb-4 pt-2",
        className
      )}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
  type StepStatus,
}

